endpoints.typeql:
# Skill details
match $s isa bioskill, has id ":sid";
fetch {
    "id": $s.id,
    "name": $s.name,
    "description": $s.description,
    "type": $s.bsi-type,
    "status": $s.bsi-status,
    "source_repo": $s.bsi-source-repo,
    "github_url": $s.bsi-github-url,
    "tool_access": $s.bsi-tool-access
};

# EDAM operation annotations
match
    $s isa bioskill, has id ":sid";
    $op isa bio-operation;
    (bsi-skill: $s, bsi-bio-op: $op) isa bsi-implements;
fetch { "op_name": $op.name, "op_edam_id": $op.edam-id };

# EDAM topic annotations
match
    $s isa bioskill, has id ":sid";
    $t isa bio-topic;
    (bsi-skill: $s, bsi-bio-topic: $t) isa bsi-covers-topic;
fetch { "topic_name": $t.name, "topic_edam_id": $t.edam-id };

match $op isa bio-operation, has edam-id ":eid";
fetch {
    "id": $op.id,
    "name": $op.name,
    "edam_id": $op.edam-id,
    "description": $op.description,
    "edam_source": $op.edam-source
};

match
    $s isa bioskill;
    $idx isa bioskill-index, has id ":id";
    (bsi-skill: $s, bsi-index: $idx) isa bsi-indexed-in;
fetch {
    "id": $s.id,
    "name": $s.name,
    "type": $s.bsi-type,
    "status": $s.bsi-status,
    "github_url": $s.bsi-github-url
};
